export interface ExecutionSummary {
  totalExecutions: number;
  verifiedCount: number;
  generatedCount: number;
  verifiedPercent: number;
  generatedPercent: number;
  successRateVerified: number;
  successRateGenerated: number;
  mostExecutedType: string;
  // Breakdown by type
  semanticQueryCount: number;
  omniQueryCount: number;
  sqlGeneratedCount: number;
  workflowCount: number;
  agentToolCount: number;
}

export interface ExecutionTimeBucket {
  timestamp: string;
  verifiedCount: number;
  generatedCount: number;
  // Optional detailed breakdown
  semanticQueryCount?: number;
  omniQueryCount?: number;
  sqlGeneratedCount?: number;
  workflowCount?: number;
  agentToolCount?: number;
}

export interface AgentExecutionStats {
  agentRef: string;
  totalExecutions: number;
  verifiedCount: number;
  generatedCount: number;
  verifiedPercent: number;
  mostExecutedType: string;
  successRate: number;
}

export type SourceType = "agent" | "workflow";

export interface ExecutionDetail {
  traceId: string;
  spanId: string;
  timestamp: string;
  executionType: ExecutionType;
  isVerified: boolean;
  // Source information
  sourceType: SourceType;
  sourceRef: string;
  // Common fields
  status: "success" | "error";
  durationMs: number;
  database?: string;
  output?: string;
  error?: string;
  // Type-specific fields
  // For semantic queries
  topic?: string;
  semanticQueryParams?: string;
  generatedSql?: string;
  // For omni queries
  integration?: string;
  endpoint?: string;
  // For SQL queries (verified)
  sql?: string;
  sqlRef?: string;
  // For SQL queries (generated)
  userQuestion?: string;
  // For workflows
  workflowRef?: string;
  // For agent tools
  agentRef?: string;
  toolInput?: string;
}
